export default function resolvePackageEntry(pkg, options = {}) {
  if (!pkg || typeof pkg !== 'object') throw new TypeError('pkg must be an object');

  const kind = options && options.kind === 'require' ? 'require' : 'import';
  const extra = Array.isArray(options && options.conditions)
    ? options.conditions.filter((c) => typeof c === 'string' && c.length)
    : [];

  const candidates = Array.from(new Set([...extra, kind, 'default']));

  const resolveTarget = (target) => {
    if (typeof target === 'string') return target;
    if (!target || typeof target !== 'object') return null;

    for (const cond of candidates) {
      if (Object.prototype.hasOwnProperty.call(target, cond)) {
        const out = resolveTarget(target[cond]);
        if (typeof out === 'string' && out.length) return out;
      }
    }
    return null;
  };

  let resolved = null;

  if (typeof pkg.exports === 'string') {
    resolved = pkg.exports;
  } else if (pkg.exports && typeof pkg.exports === 'object') {
    const root = Object.prototype.hasOwnProperty.call(pkg.exports, '.')
      ? pkg.exports['.']
      : pkg.exports;
    resolved = resolveTarget(root);
  }

  if (resolved) return resolved;

  if (kind === 'import' && typeof pkg.module === 'string' && pkg.module) return pkg.module;
  if (typeof pkg.main === 'string' && pkg.main) return pkg.main;

  throw new Error('Unable to resolve package entry');
}
